end

function LFightObjectData:RemoveShieldData(shieldData)
    if not shieldData then
        return
    end

    for i, v in pairs(self._shieldList) do
        if v.buffUniqueId == shieldData.buffUniqueId then
            self._shieldList[v.shieldUniqueId] = nil
            break
        end
    end
end

