function LFightObjectData:UpdateShieldData(shieldData)
    local shield = self._shieldList[shieldData.shieldUniqueId]
    if shield then
        local curHP = shield.curHP + shieldData.hurt
        if curHP <= 0 then
            self._shieldList[shieldData.shieldUniqueId] = nil
        else
            shield.curHP = curHP
        end
    end
end
