function LFightObjectData:InitSkillData()

    local battleObjType = self._battleObjType
    if battleObjType == LFightConst.OBJ_NORMAL then
        self:InitRoleSkill()
    -- 【G公共支持】删除神器功能相关数据
    -- elseif battleObjType == LFightConst.OBJ_ARTIFACT then
    --     self:InitArtifactData()
    elseif battleObjType == LFightConst.OBJ_TREASURE then
        self:InitTreasureSkill()
    elseif battleObjType == LFightConst.OBJ_DIVINEWEAPON then
        self:InitDivineWeaponSkill()
    end
end

function LFightObjectData:InitTreasureSkill()
    local skillList = self._skillList or {}
    self._skillRunDataList = {}
    self._skillIdToIndex = {}
    self._skillIdToSkin = {}

    for k, v in ipairs(skillList) do
        local skillId = v.skillRefId
        local skinId = v.skin or 0
        self:AddSkillMap(tonumber(skillId),false,skinId) -- 神器动效表现
        local cdRound = gModelSkill:GetSkillCdRound(skillId)

        local isPlayed = v.initCD>=0
        local isPlaying = v.initCD == 1
        --local curCd = v.initCD - 1 --默认显示第一回合
        --curCd = curCd< 0 and cdRound or curCd
        local data = {
            index = v.index,
            skillId = skillId,
            cdRound = cdRound,
            curCd = v.initCD,
            isPlayed = isPlayed,
            isPlaying = isPlaying,
            state = v.state or 0,
            exhibitionInfo = v.exhibitionInfo,
            side = self._actOn,
            skin = skinId,
        }
        self._skillRunDataList[v.index] = data

        if skillId>0 then
            self._skillIdToIndex[skillId] = v.index
            self._skillIdToSkin[skillId] = skinId
        end
    end
    self._name = self._actOn .. "的宝物"
end

function LFightObjectData:InitDivineWeaponSkill()
    local skillList = self._skillList or {}
    self._skillRunDataList = {}
    self._skillIdToIndex = {}
    self._skillIdToSkin = {}

    for k, v in ipairs(skillList) do
        local skillId = v.skillRefId
        local skinId = v.skin or 0
        self:AddSkillMap(tonumber(skillId),false,skinId) -- 神器动效表现
        local cdRound = gModelSkill:GetSkillCdRound(skillId)

        local initCD = v.initCD
        local index = v.index
        local isPlayed = initCD >= 0
        local isPlaying = initCD == 1
        local data = {
            index = index,
            skillId = skillId,
            cdRound = cdRound,
            curCd = initCD,
            isPlayed = isPlayed,
            isPlaying = isPlaying,
            state = v.state or 0,
            exhibitionInfo = v.exhibitionInfo,
            side = self._actOn,
            skin = skinId,
        }
        self._skillRunDataList[index] = data

        if skillId > 0 then
            self._skillIdToIndex[skillId] = index
            self._skillIdToSkin[skillId] = skinId
        end
    end
    self._name = self._actOn .. "的圣武"
end

function LFightObjectData:InitRoleSkill()
    local refId = self._refId
    local objName = nil

    local effectIdList = {}
    self._effectIdList = effectIdList

    if self._isMonster then
        local monRef = GameTable.MonsterAttrRef[refId]
        if not monRef then
            LogError("怪物不存在 refId"..tostring(refId))
            return false
        end

        local effectId = nil
        if self._battleObjType == LFightConst.OBJ_SUMMON then
            effectId = gModelSkill:GetSummonShowSkin(refId,self._belongSkin)
        end

        if not effectId then
            effectId = monRef.effectId
        end

        table.insert(effectIdList,effectId)

        local commandSkill = monRef.commonSkill
        self:AddSkillMap(commandSkill,true)

        local activeSkill = monRef.activeSkill
        local skillList = string.split(activeSkill,",") or {}
        for i = 1,#skillList do
            local data = skillList[i]
            local temp = string.split(data,"=")
            local skillId = tonumber(temp[1] or 0 ) or 0
            if skillId > 0 then
                self:AddSkillMap(skillId)
            end
        end

        local belongSkillGroup = monRef.belongSkillGroup
        if not string.isempty(belongSkillGroup) then
            local belongSkillList = string.split(belongSkillGroup,"|") or {}
            for i = 1,#belongSkillList do
                local skillId = tonumber(belongSkillList[i])
                if skillId  then
                    if skillId > 0 then
                        self:AddSkillMap(skillId)
                    end
                else
                    LogError("怪物技能错误 refId "..tostring(refId))
                end

            end
        end

        skillList = string.split(monRef.pasvSkill,"|")
        for i = 1,#skillList do
            local skillId = tonumber(skillList[i] or 0 ) or 0
            if skillId > 0 then
                self:AddSkillMap(skillId)
            end
        end

        objName = ccLngText(monRef.name)

        if string.isempty(objName) then
            local heroEffRef = gModelHero:GetShowEffectById(effectId)
            if  heroEffRef then
                objName = ccLngText(heroEffRef.name)
            else
                LogError(string.format("no monster effectId %s ",effectId))
            end
        end
    else
        local starLv = self._star
        local ref = GameTable.CharacterRef[refId]
        if not ref then
            return
        end


        local form = self._form

        local starRef =gModelHero:GetHeroStarRef(refId,form,starLv)

        if not starRef then return end

        local heroEffectId = nil
        if self._skinId and self._skinId>0 then
            heroEffectId = self._skinId
        else
            heroEffectId = starRef.effectId
        end

        table.insert(effectIdList,heroEffectId)

        local heroEffRef = gModelHero:GetShowEffectById(heroEffectId)

        if heroEffRef.skinState2 and heroEffRef.skinState2 > 0 then
            table.insert(effectIdList,heroEffRef.skinState2)
        end



        local skillGroup = starRef.skillGroup
        local skillList = string.split(skillGroup,",") or {}
        for i = 1,#skillList do
            local data = skillList[i]
            local temp = string.split(data,"=")
            local skillId = tonumber(temp[1] or 0 ) or 0
            if skillId > 0 then
                self:AddSkillMap(skillId)
            end
        end

        local belongSkillGroup = starRef.belongSkillGroup
        if not string.isempty(belongSkillGroup) then
            local belongSkillList = string.split(belongSkillGroup,"|") or {}
            for i = 1,#belongSkillList do
                local skillId = tonumber(belongSkillList[i])
                if skillId > 0 then
                    self:AddSkillMap(skillId)
                end
            end
        end

        local commandSkill = starRef.commonSkill
        self:AddSkillMap(commandSkill,true)

        objName = ccLngText(heroEffRef.name)
    end
    self._name = objName

end

