-- 奇景探险技能
function LFightObjectData:InitMiracleAdventureData(refId,skillList)
    self._maxCD = 0
    for i, skillId in ipairs(skillList) do
        self:AddSkillMap(tonumber(skillId))
    end
    self._name = self._actOn .. "的技能"
end

function LFightObjectData:GetSkillData(skillId,skillExpressionRefId,attackCount,useSkin)
    local expressionId = gModelSkill:GetSkillExpressionId(skillExpressionRefId,attackCount)
    if not expressionId then return end

    local skillType = nil
    local battleObjType = self._battleObjType
    local skinId = nil
    local expressId = nil
    if battleObjType == LFightConst.OBJ_TREASURE then
        skinId = self._skillIdToSkin[skillId]
        expressId = gModelSkill:GetTreasureSkinExpress(skinId,expressionId)
    elseif battleObjType == LFightConst.OBJ_DIVINEWEAPON then
        skinId = self._skillIdToSkin[skillId]
        expressId = gModelSkill:GetTreasureSkinExpress(skinId,expressionId)
        --expressId = 3401603
    else
        skinId = useSkin or self:GetShowEffId()
        expressId = gModelSkill:GetSkinExpress(skinId,expressionId,true)

        skillType = gModelSkill:GetSkinSkillType(skinId,expressionId)
    end

    local dataMap =  self._skillDataMap[expressId]
    local data = nil
    if dataMap  then
        data = dataMap[skillId]
        if data then
            return data
        end
    end

    --读取通用技能
    data = gModelSkill:GetGeneralSkillData(expressId)

    if not data then
        data = gModelSkill:GetSkillDataCommon(skillId,expressId,skinId,skillType)
    end

    return data

end


function LFightObjectData:GetSkillTransformData(skillId,expressId,expressionRefId)
    local dataMap =  self._skillDataMap[expressId]
    local data = nil
    if dataMap  then
        data = dataMap[skillId]
        if data then
            return data
        end
    end

    --读取通用技能
    data = gModelSkill:GetGeneralSkillData(expressId)

    if not data then
        local skinId = self:GetShowEffId()
        data = gModelSkill:GetSingleSkillData(skillId,expressId,skinId,expressionRefId)
    end
    return data
end

function LFightObjectData:AddSkillMap(skillId,bNormal,skinId)

    self:AddReliveSkillRecord(skillId)


    skinId = skinId or self:GetSkinId()

    local skillExpressList = gModelSkill:GetExpressionList(skillId)
    for k,v in ipairs(skillExpressList) do
        self:ParsePlaySkillID(skillId,v,bNormal,skinId)
    end
end

function LFightObjectData:ParsePlaySkillID(skillId,expressData,bNormal,skinId)
    local expressionList = gModelSkill:GetSkillPlayEffList(expressData.expressionId)
    if not expressionList then
        return
    end

    local isRole = self._battleObjType == LFightConst.OBJ_NORMAL
    local battleObjType = self._battleObjType
    local isTreasure = battleObjType == LFightConst.OBJ_TREASURE
    local isDivineWeapon = battleObjType == LFightConst.OBJ_DIVINEWEAPON
    --  local skinId = self:GetSkinId()

    for k,v in ipairs(expressionList) do
        local skillType = nil
        local expressId = nil
        if isTreasure then
            expressId = gModelSkill:GetTreasureSkinExpress(skinId,v)
        elseif isDivineWeapon then
            expressId = gModelSkill:GetDivineWeaponSkinExpress(skinId,v)
        else
            expressId = gModelSkill:GetSkinExpress(skinId,v)

            skillType = gModelSkill:GetSkinSkillType(skinId,v)
        end


            ---@type LSkillData
        local skillData = LSkillData:New()
        skillData:SetSkinSkillType(skillType)
        if skillData:InitData(skillId,expressData.skillEffId,expressId,bNormal,skinId) then
            if isTreasure then
                skillData:SetTreasureSkin(skinId)
            end

            local dataMap = self._skillDataMap[expressId]
            if not dataMap then
                dataMap = {}
                self._skillDataMap[expressId] = dataMap
            end
            dataMap[skillId]= skillData
            self._skillDataMap[expressId] = skillData
        end
    end
end

function LFightObjectData:AddReliveSkillRecord(skillId)

    if not self._reliveSkillRecord  then
        self._reliveSkillRecord = {}
    end

    local record = self._reliveSkillRecord

    local reliveType = gModelSkill:GetReliveSkillType(skillId)
    if reliveType>0 then
        local map = record[self._id]
        if not map then
            map = {}
            record[self._id] = map
        end
        map[reliveType] = true
    end
end

function LFightObjectData:GetReliveSkillRecord()
    return self._reliveSkillRecord or {}
end

function LFightObjectData:ToHpString()
    local str = string.format("id=%s, refId=%s, maxHp=%s, hp=%s, dead=%s, damage=%s, bedamage=%s",
            tostring(self._id),tostring(self._refId),tostring(self._maxHP),tostring(self._hp),tostring(self._isDead),
            tostring(self._damageCount),tostring(self._bearDamageCount))
    return str
end

