function LFightObjectData:OnRoundUpdate(round) --下一回合
    if self._battleObjType ~= LFightConst.OBJ_TREASURE then return end

    if round <= self._curRound then return end

    self._curRound = round
    for k,v in pairs(self._skillRunDataList) do
        if v.isPlayed then
            local cd = v.curCd - 1
            v.isPlaying = cd == 1
            v.curCd = cd
        end
    end
end

function LFightObjectData:OnRoundDivineUpdate(round)
    if self._battleObjType ~= LFightConst.OBJ_DIVINEWEAPON then return end

    if round <= self._curRound then return end

    self._curRound = round

    local endDivineWeaponSkill = self._endDivineWeaponSkill
    self._endDivineWeaponSkill = nil
    for k,v in pairs(self._skillRunDataList) do
        if v.isPlayed and endDivineWeaponSkill ~= v.skillId then
            local cd = v.curCd - 1
            if cd < 1 then cd = v.cdRound end
            v.isPlaying = cd == 1
            v.curCd = cd
        end
    end

end

function LFightObjectData:GenTreasureCd(skillRefId,sendEvent)
    if self._battleObjType ~= LFightConst.OBJ_TREASURE then return end

    local index = self._skillIdToIndex[skillRefId]
    if index then
        local data = self._skillRunDataList[index]
        data.isPlayed = true
        if data.curCd <=0 then
            data.curCd = data.cdRound
        end
    end

    if sendEvent then
        FireEvent(EventNames.ON_SKILL_LIST_UPDATE)
    end
end

function LFightObjectData:GenDivineWeaponCd(skillRefId,sendEvent,isBack)
    if self._battleObjType ~= LFightConst.OBJ_DIVINEWEAPON then return end

    local index = self._skillIdToIndex[skillRefId]
    if index then
        local data = self._skillRunDataList[index]
        data.isPlayed = true
        if isBack then
            if data.curCd <= 0 then
                data.curCd = data.cdRound
            end
        else
            if data.curCd <= 1 then
                data.curCd = data.cdRound
            end
        end
    end
    if sendEvent then
        --- 战斗圣武：先写这里，后续在调用
        FireEvent(EventNames.ON_DIVINE_SKILL_UPDATE)
    end
end

