    local index = self._skillIdToIndex[skillRefId]
    return index
end



function LFightObjectData:GetSkillRunDataList()
    return self._skillRunDataList or {}
end

function LFightObjectData:GetTeamName()
    return self._teamName
end

function LFightObjectData:RefreshShowEffIndex()
    local isChange = false
    local showEffIndex = 1
    for k,v in ipairs(self._buffList) do
        local buffRef = gModelSkill:GetBuffRef(v.buffId)
        if buffRef then
            if buffRef.specialShow == 1 then
                showEffIndex = 2
                isChange = true
            end
        end
    end

    if not isChange then
        for k,v in ipairs(self._pliesBuffList) do
            local buffRef = gModelSkill:GetBuffRef(v.buffId)
            if buffRef then
                if buffRef.specialShow == 1 then
                    showEffIndex = 2
                    isChange = true
                end
            end
        end
    end

    self._showEffectIndex = showEffIndex
end

function LFightObjectData:GetShowEffId()
    local index = self._showEffectIndex or 1
    local effId = self._effectIdList[index]
    if not effId then
        effId = self._effectIdList[1]
    end
    return effId
end

function LFightObjectData:UpdateRoundData(effect)
    local buffUniqueId = effect.buffUniqueId
    for k, v in ipairs(self._buffList) do
        if v.buffUniqueId == buffUniqueId then
            v.round = effect.round
            break
        end
    end

    for i,buff in ipairs(self._pliesBuffList) do
        if buff.buffUniqueIdMap[buffUniqueId] then
            buff.round = effect.round
        end
    end
end

---- 获取战斗音效
--[[1. 战斗默认音效填写战斗表现表（普攻、技1、技2）——根据表格填写读取，和原规则一致
2. 战斗进阶语音，好感度解锁技能1、技能2的，达到好感度默认使用
——根据HeroFavorabilityRef的等级判断，是否解锁战斗语音SpActionSound列填写的：skillSound1、skillSound2
——如果解锁，则使用HeroEffectRef的skillSound1、skillSound2列填写的语音文件
3. 战斗皮肤语音，根据表现表配置，穿戴皮肤后默认使用——优先级高于进阶语音，和原规则一致]]
function LFightObjectData:GetPlaySoundBattle(soundBattle,effData)
    local skinId = self._skinId
    if skinId and skinId > 0 then
        if not gModelHero:GetOriginId(skinId) then
            --- 穿戴是皮肤，由 skill 表配置的音效
            return soundBattle
        end
    end

    if not self._loveLevel then return soundBattle end

    --[[local ref = GameTable.CharacterFavorabilityRef[self._loveLevel]
    if not ref then return soundBattle end

    local SpActionSound = ref.SpActionSound
    if SpActionSound == "skillSound1" or SpActionSound == "skillSound2" then
        local effRef = gModelHero:GetHeroShowEffectRef(self._refId,self._star,skinId,self._form)
        if effRef then
            soundBattle = effRef[SpActionSound]
        end
    end]]
    local favorabilykey = gModelHeroExtra:GetHeroFavorabilitySounds(self._loveLevel,effData)
    if favorabilykey then
        local effRef = gModelHero:GetHeroShowEffectRef(self._refId,self._star,skinId,self._form)
        if effRef then
            if LOG_INFO_ENABLED then
                printInfoNR2("战斗音效打印：","好感度等级：" .. self._loveLevel ..
                        ",原音效名字：" .. soundBattle .. ",修改后音效名字：".. effRef[favorabilykey] .. ",索引的key：" .. favorabilykey)
            end
            soundBattle = effRef[favorabilykey]
        end
    end
    return soundBattle
end

